"""
HTML Sanitization Library for Crowdpulse

This module provides HTML sanitization for user-generated content
in dashboards, widgets, and annotations.

Allowed safe subset:
- Bold: <b>, <strong>
- Italic: <i>, <em>
- Links: <a> with safe href only
- Lists: <ul>, <ol>, <li>

All other tags are stripped along with their content. Event handlers,
dangerous protocols (javascript:, data:), SVG elements, CSS expressions,
and other XSS vectors are removed.
"""

import re
from html.parser import HTMLParser


# Set of allowed HTML tags (case-insensitive)
ALLOWED_TAGS = {
    'b', 'strong',
    'i', 'em',
    'a',
    'ul', 'ol', 'li',
}

# Attributes allowed on <a> tags
ALLOWED_A_ATTRIBUTES = {'href', 'title', 'target', 'rel'}

# Protocols considered safe for href attributes
SAFE_HREF_PROTOCOLS = {'http', 'https', 'mailto', 'tel', 'ftp'}

# Dangerous CSS patterns to strip from style attributes
DANGEROUS_CSS_PATTERNS = [
    re.compile(r'expression\s*\(', re.IGNORECASE),
    re.compile(r'-moz-binding\s*:', re.IGNORECASE),
    re.compile(r'behavior\s*:', re.IGNORECASE),
    re.compile(r'@import', re.IGNORECASE),
]


def _is_event_handler_attr(attr_name: str) -> bool:
    """Check if an attribute is an event handler (on* where * starts with a letter)."""
    attr_lower = attr_name.lower()
    if attr_lower.startswith('on') and len(attr_lower) > 2:
        return attr_lower[2:3].isalpha()
    return False


def _is_safe_href(href: str) -> bool:
    """Check if a href uses a safe protocol, decoding entities and stripping whitespace."""
    if not href:
        return False

    decoded = html.unescape(href)
    stripped = decoded.strip()

    if not stripped:
        return False

    # Remove all whitespace and control characters
    cleaned = re.sub(r'[\s\x00-\x1f]', '', stripped)
    lower = cleaned.lower()

    # Check against safe protocols
    for protocol in SAFE_HREF_PROTOCOLS:
        if lower.startswith(protocol + ':'):
            after_colon = lower[len(protocol) + 1:]
            # Reject empty or suspicious content after protocol
            if not after_colon or re.search(r'alert\s*\(', after_colon):
                return False
            return True

    # Relative URLs (no protocol) are safe
    if not re.match(r'^[a-zA-Z][a-zA-Z0-9+.\-]*:', cleaned):
        return True

    # Unknown protocol - reject
    return False


def _sanitize_style(style_value: str) -> str:
    """Remove dangerous CSS patterns from a style value."""
    if not style_value:
        return style_value
    result = style_value
    for pattern in DANGEROUS_CSS_PATTERNS:
        result = pattern.sub('', result)
    return result.strip() if result.strip() else ""


def sanitize_html(html_content: str) -> str:
    """Sanitize user-provided HTML content.

    Allows a safe subset of HTML tags while stripping
    potentially dangerous content including:
    - Script tags and their content
    - Event handler attributes (onclick, onerror, onload, etc.)
    - JavaScript URLs in href attributes
    - SVG elements and their event handlers
    - CSS expressions, -moz-binding, behavior, @import
    - HTML comments and processing instructions
    - Numeric entity injection (null bytes, etc.)
    - Data URI payloads

    Args:
        html_content: Raw HTML string from user input

    Returns:
        Sanitized HTML string safe for rendering
    """
    if html_content is None:
        return ""
    if not isinstance(html_content, str):
        return str(html_content)
    if not html_content:
        return ""

    # Strip null bytes which can bypass some sanitizers
    html_content = html_content.replace('\x00', '')

    sanitizer = HTMLSanitizer()
    try:
        sanitizer.feed(html_content)
    except Exception:
        return ""

    return sanitizer.get_sanitized_html()


class HTMLSanitizer(HTMLParser):
    """An HTML parser that sanitizes content by only allowing a safe subset
    of HTML tags and attributes while stripping all potentially dangerous content.
    """

    def __init__(self):
        super().__init__(convert_charrefs=True)
        self.result = []

    def handle_starttag(self, tag, attrs):
        tag_lower = tag.lower()

        # Strip all dangerous/unknown tags entirely (don't even emit them)
        if tag_lower not in ALLOWED_TAGS:
            return

        # Build list of safe attributes
        safe_attrs = []
        for attr_name, attr_value in attrs:
            attr_lower = attr_name.lower()

            # Strip event handler attributes
            if _is_event_handler_attr(attr_lower):
                continue

            # For <a> tags, validate href
            if tag_lower == 'a' and attr_lower == 'href':
                if _is_safe_href(attr_value or ''):
                    safe_attrs.append((attr_lower, attr_value))
                continue

            # For <a> tags, only allow whitelisted attributes
            if tag_lower == 'a' and attr_lower not in ALLOWED_A_ATTRIBUTES:
                continue

            # Strip dangerous CSS from style attributes
            if attr_lower == 'style' and attr_value is not None:
                sanitized = _sanitize_style(attr_value)
                if sanitized:
                    safe_attrs.append((attr_lower, sanitized))
                continue

            # For non-<a> allowed tags, keep all non-event-handler attrs
            safe_attrs.append((attr_lower, attr_value))

        # Reconstruct the tag with safe attributes
        if safe_attrs:
            attr_str = ' '.join(
                name if value is None else f'{name}="{self._escape_attr(value)}"'
                for name, value in safe_attrs
            )
            self.result.append(f'<{tag_lower} {attr_str}>')
        else:
            self.result.append(f'<{tag_lower}>')

    def handle_endtag(self, tag):
        tag_lower = tag.lower()
        if tag_lower in ALLOWED_TAGS:
            self.result.append(f'</{tag_lower}>')

    def handle_data(self, data):
        self.result.append(data)

    def handle_entityref(self, name):
        # Re-encode standard entities to characters
        entity_map = {
            'amp': '&',
            'lt': '<',
            'gt': '>',
            'quot': '"',
            'apos': "'",
            'nbsp': '\u00a0',
        }
        self.result.append(entity_map.get(name, f'&{name};'))

    def handle_charref(self, name):
        try:
            if name.startswith('x') or name.startswith('X'):
                char_code = int(name[1:], 16)
            else:
                char_code = int(name)
            # Only allow printable ASCII and common whitespace
            if 32 <= char_code <= 126 or char_code in (9, 10, 13):
                self.result.append(chr(char_code))
        except (ValueError, OverflowError):
            pass

    def handle_comment(self, data):
        # Strip HTML comments entirely
        pass

    def handle_decl(self, decl):
        # Strip doctype declarations
        pass

    def handle_pi(self, data):
        # Strip processing instructions
        pass

    def error(self, message):
        pass

    def get_sanitized_html(self):
        return ''.join(self.result)

    @staticmethod
    def _escape_attr(value):
        """Escape a value for use inside an HTML attribute."""
        return value.replace('&', '&amp;').replace('"', '&quot;')

